13	interface NotificationItem {
14	  id: string;
15	  type: string;
16	  title: string;
17	  body: string;
18	  read: boolean;
19	  relatedTicketId?: string;
20	  relatedAssetId?: string;
21	  createdAt: string;
22	}
23	
24	export default function NotificationsPage() {
25	  const { user, setUnreadNotifications } = useAuth();
26	  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
27	  const [loading, setLoading] = useState(true);
28	  const [error, setError] = useState<string | null>(null);
29	
30	  const fetchNotifications = async () => {
31	    setLoading(true);
32	    setError(null);
33	    try {
34	      // Derive notifications from tickets
35	      const res = await apiFetch<PaginatedResponse<{ id: string; type: string; status: string; createdAt: string; updatedAt: string }>>(
36	        "/api/tickets",
37	        { params: { page: 1, pageSize: 50 } },
38	      );
39	      const items: NotificationItem[] = res.data.map((t) => ({
40	        id: t.id,
41	        type: "APPROVAL_RESULT",
42	        title: t.type === "APPLY" ? "申领工单" : t.type === "REPAIR" ? "报修工单" : t.type === "RETURN" ? "归还工单" : "调拨工单",
43	        body: `状态更新为: ${t.status}`,
44	        read: ["COMPLETED", "CANCELLED", "REJECTED"].includes(t.status),
45	        relatedTicketId: t.id,
46	        createdAt: t.updatedAt,
47	      }));
48	      setNotifications(items);
49	      const unread = items.filter((n) => !n.read).length;
50	      setUnreadNotifications(unread);
51	    } catch (err) {
52	      setError(err instanceof Error ? err.message : "加载失败");
53	    } finally {
54	      setLoading(false);
55	    }
56	  };
57	
58	  useEffect(() => {
59	    fetchNotifications();
60	  }, []);
61	
62	  const handleMarkAllRead = () => {
63	    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
64	    setUnreadNotifications(0);
65	  };
66	
67	  const typeIcon = (type: string) => {
68	    const map: Record<string, string> = {
69	      APPROVAL_REQUEST: "📋",
70	      APPROVAL_RESULT: "✅",
71	      PICKUP_READY: "📦",
72	      REPAIR_UPDATE: "🔧",
73	      WARRANTY_EXPIRY: "⚠️",
74	      TRANSFER_REQUEST: "🔄",
75	      RETURN_SUBMITTED: "📤",
76	    };
77	    return map[type] ?? "📩";
78	  };
79	
80	  if (loading) {
81	    return (
82	      <div className="flex flex-1 items-center justify-center p-4">
83	        <div className="w-full max-w-2xl space-y-4">
84	          <Skeleton className="h-8 w-32" />
85	          {[1, 2, 3, 4, 5].map((i) => (
86	            <Skeleton key={i} className="h-20 rounded-lg" />
87	          ))}
88	        </div>
89	      </div>
90	    );
91	  }
92	
93	  if (error !== null) {
94	    return (
95	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
96	        <p className="text-destructive">{error}</p>
97	        <Button onClick={fetchNotifications}>重试</Button>
98	      </div>
99	    );
100	  }
101	
102	  return (
103	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-2xl mx-auto w-full">
104	      <div className="flex items-center justify-between">
105	        <PageHeader title="通知中心" />
106	        {notifications.length > 0 && (
107	          <Button variant="outline" size="sm" onClick={handleMarkAllRead}>
108	            全部标记已读
109	          </Button>
110	        )}
111	      </div>
112	
113	      {notifications.length === 0 ? (
114	        <EmptyState icon={Inbox} title="暂无通知" />
115	      ) : (
116	        <div className="space-y-2">
117	          {notifications.map((n) => (
118	            <div
119	              key={n.id}
120	              className={`rounded-lg border p-4 transition-colors hover:bg-muted/50 ${
121	                !n.read ? "border-l-4 border-l-primary" : ""
122	              }`}
123	            >
124	              <div className="flex items-start gap-3">
125	                <span className="text-xl">{typeIcon(n.type)}</span>
126	                <div className="flex-1 min-w-0">
127	                  <div className="flex items-center justify-between">
128	                    <p className={`text-sm font-medium ${!n.read ? "text-foreground" : "text-muted-foreground"}`}>
129	                      {n.title}
130	                    </p>
131	                    <span className="text-xs text-muted-foreground whitespace-nowrap ml-2">
132	                      {new Date(n.createdAt).toLocaleString("zh-CN")}
133	                    </span>
134	                  </div>
135	                  <p className="mt-1 text-sm text-muted-foreground line-clamp-2">{n.body}</p>
136	                  {n.relatedTicketId && (
137	                    <Link
138	                      href={`/tickets/${n.relatedTicketId}`}
139	                      className="mt-2 inline-block text-xs text-primary underline-offset-4 hover:underline"
140	                    >
141	                      查看工单
142	                    </Link>
143	                  )}
144	                </div>
145	              </div>
146	            </div>
147	          ))}
148	        </div>
149	      )}
150	    </div>
151	  );
152	}
