215	          <p className="text-sm font-medium">申请理由</p>
216	          <p className="text-sm text-muted-foreground">{ticket.reason}</p>
217	        </CardContent>
218	      </Card>
219	
220	      {/* Actions */}
221	      <div className="flex flex-wrap gap-2">
222	        {canApprove && (
