10	import { PageHeader } from "@/components/page-header";
11	import { Card, CardContent } from "@/components/ui/card";
12	
13	interface ChatMessage {
14	  role: "user" | "assistant";
15	  content: string;
16	}
17	
18	interface ChatResponse {
19	  ok: boolean;
20	  data?: {
21	    intent?: string;
22	    reply: string;
23	    needConfirmation?: boolean;
24	    pendingAction?: {
25	      type: string;
26	      description: string;
27	      params: Record<string, unknown>;
28	    } | null;
29	    confirmationToken?: string;
30	  };
31	  error?: string;
32	  reply?: string;
33	}
34	
35	export default function ChatPage() {
36	  const { user } = useAuth();
37	  const router = useRouter();
38	  const [messages, setMessages] = useState<ChatMessage[]>([
39	    { role: "assistant", content: "你好！我是 IT 助手，有什么可以帮助你的吗？你可以查询资产信息、保修状态、工单进度，或提交申领/报修申请。" },
40	  ]);
41	  const [input, setInput] = useState("");
42	  const [loading, setLoading] = useState(false);
43	  const [degraded, setDegraded] = useState(false);
44	  const [confirmDialog, setConfirmDialog] = useState<{
45	    description: string;
46	    actionType: string;
47	    token: string;
48	  } | null>(null);
49	  const messagesEndRef = useRef<HTMLDivElement>(null);
50	
51	  // Auto scroll to bottom
52	  useEffect(() => {
53	    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
54	  }, [messages]);
55	
56	  const handleSend = async () => {
57	    if (!input.trim() || loading) return;
58	    const userMsg: ChatMessage = { role: "user", content: input.trim() };
59	    setMessages((prev) => [...prev, userMsg]);
60	    setInput("");
61	    setLoading(true);
62	
63	    try {
64	      const history = messages.slice(1).map((m) => ({ role: m.role, content: m.content }));
65	      const res = await apiFetch<ChatResponse>("/api/ai/chat", {
66	        method: "POST",
67	        body: { message: userMsg.content, history },
68	      });
69	
70	      if (res.ok && res.data) {
71	        setDegraded(false);
72	        const assistantMsg: ChatMessage = {
73	          role: "assistant",
74	          content: res.data.reply,
75	        };
76	        setMessages((prev) => [...prev, assistantMsg]);
77	
78	        if (res.data.needConfirmation && res.data.pendingAction && res.data.confirmationToken) {
79	          setConfirmDialog({
80	            description: res.data.pendingAction.description,
81	            actionType: res.data.pendingAction.type,
82	            token: res.data.confirmationToken,
83	          });
84	        }
85	      } else {
86	        // Degraded mode or error
87	        setDegraded(true);
88	        const reply = res.reply ?? res.data?.reply ?? "AI 助手暂时不可用";
89	        setMessages((prev) => [...prev, { role: "assistant", content: reply }]);
90	      }
91	    } catch (err) {
92	      setDegraded(true);
93	      setMessages((prev) => [
94	        ...prev,
95	        { role: "assistant", content: "AI 助手暂时不可用，你可以通过「我的资产」查看资产信息，或通过「申领设备」/「报修」提交申请。" },
96	      ]);
97	    } finally {
98	      setLoading(false);
99	    }
100	  };
101	
102	  const handleConfirm = () => {
103	    if (!confirmDialog) return;
104	    const { actionType } = confirmDialog;
105	    setConfirmDialog(null);
106	    if (actionType === "create_apply") {
107	      router.push("/apply");
108	    } else if (actionType === "create_repair") {
109	      router.push("/tickets");
110	    }
111	  };
112	
113	  const handleKeyDown = (e: React.KeyboardEvent) => {
114	    if (e.key === "Enter" && !e.shiftKey) {
115	      e.preventDefault();
116	      handleSend();
117	    }
118	  };
119	
120	  return (
121	    <div className="flex flex-1 flex-col h-full max-w-2xl mx-auto w-full p-4">
122	      <PageHeader title="AI 助手" description="智能问答，协助处理 IT 事务" />
123	
124	      {/* Chat Messages */}
125	      <div className="flex-1 overflow-y-auto space-y-4 mb-4 min-h-0">
126	        {messages.map((msg, i) => (
127	          <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
128	            <div
129	              className={`max-w-[80%] rounded-lg px-4 py-2 ${
130	                msg.role === "user"
131	                  ? "bg-primary text-primary-foreground"
132	                  : "bg-muted text-foreground"
133	              }`}
134	            >
135	              <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
136	            </div>
137	          </div>
138	        ))}
139	
140	        {/* Typing Indicator */}
141	        {loading && (
142	          <div className="flex justify-start">
143	            <div className="rounded-lg bg-muted px-4 py-3">
144	              <div className="flex gap-1">
145	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:0ms]" />
146	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:150ms]" />
147	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:300ms]" />
148	              </div>
149	            </div>
150	          </div>
151	        )}
152	
153	        {/* Degraded Hint */}
154	        {degraded && !loading && (
155	          <Card size="sm" className="border-amber-200 dark:border-amber-800 bg-amber-50/50 dark:bg-amber-950/20">
156	            <CardContent>
157	              <p className="text-xs text-amber-800 dark:text-amber-200">AI 服务降级中，部分功能可能不可用</p>
158	            </CardContent>
159	          </Card>
160	        )}
161	
162	        <div ref={messagesEndRef} />
163	      </div>
164	
165	      {/* Input Area */}
166	      <div className="flex gap-2">
167	        <Textarea
168	          value={input}
169	          onChange={(e) => setInput(e.target.value)}
170	          onKeyDown={handleKeyDown}
171	          placeholder="输入你的问题..."
172	          rows={1}
173	          className="flex-1 resize-none"
174	        />
175	        <Button onClick={handleSend} disabled={loading || !input.trim()}>
176	          发送
177	        </Button>
178	      </div>
179	
180	      {/* Confirmation Dialog */}
181	      <Dialog open={confirmDialog !== null} onOpenChange={(open) => { if (!open) setConfirmDialog(null); }}>
182	        <DialogContent showCloseButton>
183	          <DialogHeader>
184	            <DialogTitle>确认操作</DialogTitle>
185	          </DialogHeader>
186	          <p className="text-sm text-muted-foreground">{confirmDialog?.description}</p>
187	          <DialogFooter>
188	            <Button variant="outline" onClick={() => setConfirmDialog(null)}>
189	              取消
190	            </Button>
191	            <Button onClick={handleConfirm}>
192	              确认
193	            </Button>
194	          </DialogFooter>
195	        </DialogContent>
196	      </Dialog>
197	    </div>
198	  );
199	}
